// Chat history persistence across tab switches
// Keeps messages alive when user navigates away from ARIA Chat tab

import React, { createContext, useContext, useState } from "react";

const ChatContext = createContext(null);

const INITIAL_MESSAGE = {
  role: "assistant",
  content:
    "ARIA online. I'm monitoring 7 AI models across your plant fleet — " +
    "forecasting, demand, energy, anomaly detection, plant behavior, " +
    "predictive maintenance, and failure prediction. Ask me anything.",
};

export function ChatProvider({ children }) {
  const [messages, setMessages] = useState([INITIAL_MESSAGE]);
  const [loading,  setLoading]  = useState(false);

  const addMessage = (msg) => setMessages(prev => [...prev, msg]);
  const clearChat  = ()    => setMessages([INITIAL_MESSAGE]);

  return (
    <ChatContext.Provider value={{ messages, setMessages, loading, setLoading, addMessage, clearChat }}>
      {children}
    </ChatContext.Provider>
  );
}

export function useChatStore() {
  const ctx = useContext(ChatContext);
  if (!ctx) throw new Error("useChatStore must be used inside <ChatProvider>");
  return ctx;
}
